import type { Order } from "./Order.ts";
import { isBeforeInstant } from "../../shared/utils/date.ts";

/** Owns order cancellation eligibility decisions. */
export class OrderPolicy {
  canCancel(order: Order, now: Date): boolean {
    return order.status === "pending" && this.canCancelBeforeDeadline(order.cancellationDeadline, now);
  }

  canCancelBeforeDeadline(cancellationDeadline: Date, now: Date): boolean {
    return isBeforeInstant(now, cancellationDeadline);
  }
}

import assert from "node:assert/strict";
import test from "node:test";
import type {
  AuthorizationService,
  Clock,
  OrderRepository,
  TransactionManager
} from "../application/OrderService.ts";
import { OrderService } from "../application/OrderService.ts";
import type { Order } from "../domain/Order.ts";

class InMemoryOrderRepository implements OrderRepository {
  readonly saved: Order[] = [];
  private readonly orders = new Map<string, Order>();

  constructor(order: Order) {
    this.orders.set(order.id, order);
  }

  async findById(orderId: string): Promise<Order | undefined> {
    return this.orders.get(orderId);
  }

  async save(order: Order): Promise<void> {
    this.saved.push(order);
    this.orders.set(order.id, order);
  }
}

class RecordingTransactionManager implements TransactionManager {
  runs = 0;

  async run<T>(work: () => Promise<T>): Promise<T> {
    this.runs += 1;
    return work();
  }
}

const ownerAuthorization: AuthorizationService = {
  assertCanCancelOrder(actorId: string, order: Order): void {
    if (actorId !== order.customerId) {
      throw new Error("ORDER_CANCEL_FORBIDDEN");
    }
  }
};

function fixedClock(now: string): Clock {
  return {
    now: () => new Date(now)
  };
}

function pendingOrder(deadline: string): Order {
  return {
    id: "order-1",
    customerId: "customer-1",
    status: "pending",
    cancellationDeadline: new Date(deadline)
  };
}

function buildService(order: Order, now: string): {
  orders: InMemoryOrderRepository;
  service: OrderService;
  transactions: RecordingTransactionManager;
} {
  const orders = new InMemoryOrderRepository(order);
  const transactions = new RecordingTransactionManager();
  const service = new OrderService({
    orders,
    authorization: ownerAuthorization,
    transactions,
    clock: fixedClock(now)
  });

  return { orders, service, transactions };
}

test("cancels an authorized pending order through the existing service workflow", async () => {
  const { orders, service, transactions } = buildService(
    pendingOrder("2026-06-20T12:00:00.000Z"),
    "2026-06-20T11:00:00.000Z"
  );

  const cancelled = await service.cancelOrder("order-1", "customer-1");

  assert.equal(transactions.runs, 1);
  assert.equal(cancelled.status, "cancelled");
  assert.equal(cancelled.cancelledAt?.toISOString(), "2026-06-20T11:00:00.000Z");
  assert.equal(orders.saved.length, 1);
});

test("allows cancellation immediately before the deadline", async () => {
  const { orders, service } = buildService(
    pendingOrder("2026-06-20T12:00:00.000Z"),
    "2026-06-20T11:59:59.999Z"
  );

  const cancelled = await service.cancelOrder("order-1", "customer-1");

  assert.equal(cancelled.status, "cancelled");
  assert.equal(orders.saved.length, 1);
});

test("rejects cancellation at the deadline", async () => {
  const { orders, service } = buildService(
    pendingOrder("2026-06-20T12:00:00.000Z"),
    "2026-06-20T12:00:00.000Z"
  );

  await assert.rejects(
    () => service.cancelOrder("order-1", "customer-1"),
    /ORDER_CANCELLATION_DEADLINE_EXPIRED/
  );
  assert.equal(orders.saved.length, 0);
});

test("rejects cancellation after the deadline", async () => {
  const { orders, service } = buildService(
    pendingOrder("2026-06-20T12:00:00.000Z"),
    "2026-06-20T12:00:00.001Z"
  );

  await assert.rejects(
    () => service.cancelOrder("order-1", "customer-1"),
    /ORDER_CANCELLATION_DEADLINE_EXPIRED/
  );
  assert.equal(orders.saved.length, 0);
});

import type { Order } from "../domain/Order.ts";
import { markOrderCancelled } from "../domain/Order.ts";
import { OrderPolicy } from "../domain/OrderPolicy.ts";

/** Persistence boundary used by order application services. */
export interface OrderRepository {
  findById(orderId: string): Promise<Order | undefined>;
  save(order: Order): Promise<void>;
}

/** Authorization boundary for order actions. */
export interface AuthorizationService {
  assertCanCancelOrder(actorId: string, order: Order): Promise<void> | void;
}

/** Transaction boundary preserving cancellation write atomicity. */
export interface TransactionManager {
  run<T>(work: () => Promise<T>): Promise<T>;
}

/** Clock seam for deterministic deadline tests. */
export interface Clock {
  now(): Date;
}

const systemClock: Clock = {
  now: () => new Date()
};

/** Application service that orchestrates order cancellation. */
export class OrderService {
  private readonly orders: OrderRepository;
  private readonly authorization: AuthorizationService;
  private readonly transactions: TransactionManager;
  private readonly policy: OrderPolicy;
  private readonly clock: Clock;

  constructor(dependencies: {
    orders: OrderRepository;
    authorization: AuthorizationService;
    transactions: TransactionManager;
    policy?: OrderPolicy;
    clock?: Clock;
  }) {
    this.orders = dependencies.orders;
    this.authorization = dependencies.authorization;
    this.transactions = dependencies.transactions;
    this.policy = dependencies.policy ?? new OrderPolicy();
    this.clock = dependencies.clock ?? systemClock;
  }

  async cancelOrder(orderId: string, actorId: string): Promise<Order> {
    return this.transactions.run(async () => {
      const order = await this.orders.findById(orderId);

      if (!order) {
        throw new Error("ORDER_NOT_FOUND");
      }

      await this.authorization.assertCanCancelOrder(actorId, order);

      const cancelledAt = this.clock.now();
      if (!this.policy.canCancel(order, cancelledAt)) {
        throw new Error("ORDER_CANCELLATION_DEADLINE_EXPIRED");
      }

      const cancelled = markOrderCancelled(order, cancelledAt);
      await this.orders.save(cancelled);

      return cancelled;
    });
  }
}

