/** Returns true when value is strictly earlier than boundary. */
export function isBeforeInstant(value: Date, boundary: Date): boolean {
  return value.getTime() < boundary.getTime();
}

/** Order lifecycle states relevant to cancellation. */
export type OrderStatus = "pending" | "cancelled" | "fulfilled";

/** Domain state needed by the order cancellation workflow. */
export interface Order {
  id: string;
  customerId: string;
  status: OrderStatus;
  cancellationDeadline: Date;
  cancelledAt?: Date;
}

/** Returns a cancelled copy of an order without persisting side effects. */
export function markOrderCancelled(order: Order, cancelledAt: Date): Order {
  return {
    ...order,
    status: "cancelled",
    cancelledAt
  };
}

